import { useEffect, useState } from "react";
import { Alchemy, Network } from "alchemy-sdk";
import "./styles.css";

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};

const alchemy = new Alchemy(settings);

export default function AccountsPage() {
  const [address, setAddress] = useState("");
  const [balance, setBalance] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function lookupBalance() {
    try {
      setLoading(true);
      setError("");
      setBalance(null);

      if (!address) {
        setError("Please enter an Ethereum address.");
        return;
      }

      const rawBalance = await alchemy.core.getBalance(address);
      const eth = Number(rawBalance) / 1e18;

      setBalance(eth.toFixed(6));
    } catch (err) {
      setError("Invalid address or network error.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="container">
      <h1 className="title">NFT Lookup</h1>

      <div className="card">
        <h2>🔍 Lookup NFT Metadata</h2>

        <input
          className="input"
          placeholder="NFT Contract Address..."
          value={nftContract}
          onChange={(e) => setNftContract(e.target.value)}
        />

        <input
          className="input"
          placeholder="Token ID..."
          value={tokenId}
          onChange={(e) => setTokenId(e.target.value)}
        />

        <button className="button" onClick={fetchNFT} disabled={loading}>
          {loading ? "Fetching..." : "Fetch NFT"}
        </button>

        {error && <p className="error">{error}</p>}

        {nftData && (
          <div className="nft-info">
            <p><strong>Name:</strong> {nftData.title}</p>
            <p><strong>Description:</strong> {nftData.description}</p>
            <p><strong>Floor Price:</strong> {floorPrice} ETH</p>
            {nftData.media[0]?.gateway && (
              <img
                src={nftData.media[0].gateway}
                alt="NFT"
                style={{ maxWidth: "200px", marginTop: "10px" }}
              />
            )}
          </div>
        )}
      </div>
    </div>
  );
}
